import * as React from 'react';
import Typography from '@mui/material/Typography';
import {GatsbyImage, getImage} from 'gatsby-plugin-image';
import Grid from '@mui/material/Unstable_Grid2';
import Box from '@mui/material/Box';
import Layout from '../components/layout';
import * as styles from '../components/index.module.css';
import {graphql, useStaticQuery} from 'gatsby';
import FeedIcon from '@mui/icons-material/Feed';
import CardActions from '@mui/material/CardActions';
import Container from '@mui/material/Container';
import Button from '@mui/material/Button';
import {CardActionArea, Chip} from '@mui/material';
import Paper from '@mui/material/Paper';
import Divider from '@mui/material/Divider';
import Link from '@mui/material/Link';
import Card from '@mui/material/Card';
import CardHeader from '@mui/material/CardHeader';
import CardMedia from '@mui/material/CardMedia';
import CardContent from '@mui/material/CardContent';
import Avatar from '@mui/material/Avatar';
import {red} from '@mui/material/colors';
import ButtonBase from '@mui/material/ButtonBase';
import {styled} from '@mui/material/styles';
import Seo from '../components/seo';
import SimpleVideo from '../components/video';
import Stack from '@mui/material/Stack';

const Info = ({data}) => {

  return (<Box sx={{marginTop: '40px', mb: 1}}>
    <Container maxWidth="xl">
      <Grid container spacing={5}>
        <Grid sm={12} xs={12} md={5} display="flex" alignItems="center">
          <GatsbyImage imgClassName={styles.bannerImage}
                       image={getImage(data.image?.localFile)}
                       alt=""/></Grid>
        <Grid sm={12} xs={12} md={7}
              dangerouslySetInnerHTML={{__html: data.content.data.content}}></Grid>
      </Grid>
    </Container>
  </Box>);
};

const NewsCard = ({news}) => {
  return (<Box sx={{flexGrow: 1, pb: 4}}>

    <Grid container display="flex" justifyContent="center"
          alignItems="center" spacing={2}
          columns={{xs: 4, sm: 8, md: 12}}>
      {news?.map((item, index) => {
            return (
                <Grid key={index} md={4} sm={6} xs={12} lg={4} xl={4} display="flex"
                      justifyContent="center">
                  <Card sx={{cursor:'pointer'}} onClick={()=>window.location.href=`/news/${item.id}`}>
                    <CardHeader
                        avatar={
                          <Avatar sx={{bgcolor: red[500]}} aria-label="recipe">
                            <FeedIcon/>
                          </Avatar>
                        }
                        title={<Link underline={'hover'}
                                     color="inherit">{item.title}</Link>}
                        subheader={item.time}
                    />
                    <CardMedia
                        component="img"
                        height="194"
                        image={item.media[0]?.localFile.publicURL}
                        alt={item.title}
                    />
                    <CardContent>
                      <Typography component="div" className={styles.textClamp}
                                  variant="body2" color="text.secondary">
                        {item.desc}
                      </Typography>
                    </CardContent>
                    <CardActions disableSpacing sx={{textAlign: 'end'}}>
                      <Button size="small" href={`/news/${item.id}`}>
                        查看详情
                      </Button>
                    </CardActions>

                  </Card>

                </Grid>
            );

          },
      )}
    </Grid>
  </Box>);

};

const ImageButton = styled(ButtonBase)(({theme}) => ({
  position: 'relative',
  height: 300,
  [theme.breakpoints.down('sm')]: {
    width: '100% !important', // Overrides inline-style
    height: 100,
  },
  '&:hover, &.Mui-focusVisible': {
    zIndex: 1,
    '& .MuiImageBackdrop-root': {
      opacity: 0.15,
    },
    '& .MuiImageMarked-root': {
      opacity: 0,
    },
    '& .MuiTypography-root': {
      border: '4px solid currentColor',
    },
  },
}));

const ImageSrc = styled('span')({
  position: 'absolute',
  left: 0,
  right: 0,
  top: 0,
  bottom: 0,
  backgroundSize: 'cover',
  backgroundPosition: 'center 40%',
});

const Image = styled('span')(({theme}) => ({
  position: 'absolute',
  left: 0,
  right: 0,
  top: 0,
  bottom: 0,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: theme.palette.common.white,
}));

const ImageBackdrop = styled('span')(({theme}) => ({
  position: 'absolute',
  left: 0,
  right: 0,
  top: 0,
  bottom: 0,
  backgroundColor: theme.palette.common.black,
  opacity: 0.4,
  transition: theme.transitions.create('opacity'),
}));

const ImageMarked = styled('span')(({theme}) => ({
  height: 3,
  width: 18,
  backgroundColor: theme.palette.common.black,
  position: 'absolute',
  bottom: 4,
  left: 'calc(50% - 9px)',
  transition: theme.transitions.create('opacity'),
}));

const HotCard = ({product}) => {

  return (<Card
      sx={{maxWidth: '100%', mx: 1, my: 1}}>
    <CardActionArea>
      <CardMedia
          component="img"
          height="200"
          image={product.image.localFile.publicURL}
          alt={product.title}
      />
      <CardContent>
        <Typography gutterBottom variant="h5" component="div">
          {product.title}
        </Typography>

      </CardContent>
    </CardActionArea>
    <CardActions>
      <Button size="small" color="primary">
        了解更多
      </Button>
    </CardActions>
  </Card>);
};
const HotProducts = ({products}) => {
  return (<Box sx={{
        display: 'flex',
        justifyContent: 'center',
        flexWrap: 'wrap',
        minWidth: 300,
        width: '100%',
      }}>
          {products.map((item, index) => (
              <Stack key={index} spacing={0}>


                <Typography
                    component="span"
                    variant="subtitle1"
                    color="inherit"
                    noWrap
                    sx={{
                      width: 320,
                      textAlign:'center',
                      position: 'relative',
                      p: 4,
                      pt: 2,
                      pb: (theme) => `calc(${theme.spacing(1)} + 6px)`,
                    }}
                >
                  <Link  color="inherit" href={`/product/${item.id}`} underline={'none'}>
                  {item.title}
                  </Link>
                  <ImageMarked className="MuiImageMarked-root"/>
                </Typography>

              <ImageButton
                  focusRipple
                  href={`/product/${item.id}`}
                  key={index}
                  style={{
                    width: 320,
                  }}
              >
                <ImageSrc
                    style={{backgroundImage: `url(${item.image.localFile.publicURL})`}}/>
                <ImageBackdrop className="MuiImageBackdrop-root"/>
                <Image>

                </Image>
              </ImageButton>
              </Stack>
          ))}
      </Box>
  );
};

const IndexPage = () => {

  const {
    strapiHotProduct,
    strapiHomeVideo,
    allStrapiCorporateNew,
    strapiCorporateProfile,
  } = useStaticQuery(graphql`
  query HomeQuery {
    strapiHomeVideo {
    video {
      localFile {
        publicURL
      }
    }
  }
  allStrapiCorporateNew(limit: 3, sort: {time: DESC}) {
    nodes {
      desc
      id
      time
      title
       media {
        localFile {
        publicURL
             childImageSharp {
            gatsbyImageData
          }
        }
      }
    }

}
    strapiHotProduct{
     products {
        title
        id
        image {
          localFile {
          publicURL
            childImageSharp {
              gatsbyImageData
            }
          }
        }
      }
  }
  strapiCorporateProfile {
    content {
      data {
        content
      }
    }
    image {
      localFile {

        childImageSharp {
          gatsbyImageData
        }
      }
    }
  }
  allStrapiBanner {
    nodes {
      image {
        localFile {
        publicURL
          childImageSharp {
            gatsbyImageData
          }
        }
      }
      title
      id
    }
  }
}`);

  return (<Layout>


    <Paper className={styles.pager}>
      {strapiHomeVideo?.video && <Box className={styles.videoBox}>
        <SimpleVideo style={{
          borderTopLeftRadius: '0.75rem',
          borderTopRightRadius: '0.75rem',
        }}
                     src={strapiHomeVideo.video.localFile.publicURL}></SimpleVideo></Box>}
      <Info data={strapiCorporateProfile}></Info>


      <Divider sx={{mt: 2, mb: 2}}>
        <Chip sx={{height: '40px'}} label={<>
          <div>HOT PRODUCT</div>
          <div style={{fontSize: '8px', opacity: .6}}>热门产品</div>
        </>}> </Chip>
      </Divider>
      <HotProducts products={strapiHotProduct.products}></HotProducts>
      <Divider sx={{mt: 2, mb: 2}}>

        <Chip sx={{height: '40px'}} label={<>
          <div>NEWS CENTER</div>
          <div style={{fontSize: '8px', opacity: .6}}>新闻咨询</div>
        </>}> </Chip>
      </Divider>

      <NewsCard news={allStrapiCorporateNew.nodes || []}></NewsCard>

    </Paper>

  </Layout>);
};

/**
 * Head export to define metadata for the page
 *
 * See: https://www.gatsbyjs.com/docs/reference/built-in-components/gatsby-head/
 */
export const Head = () => <Seo title=""/>;

export default IndexPage;

